// --- types.d.ts ---
// types.d.ts
export interface ChemicalElement {
  atomicNumber: number;
  symbol: string;
  name: string;
  atomicWeight: number;
  category: string;
  row: number;
  col: number;
}

export interface Props {
  elements: ChemicalElement[];
}

export interface HookReturn {
  searchTerm: string;
  setSearchTerm: (term: string) => void;
  selectedElement: ChemicalElement | null;
  setSelectedElement: (element: ChemicalElement | null) => void;
  filteredElements: ChemicalElement[];
  categories: string[];
  isHighlighted: (element: ChemicalElement) => boolean;
}

export interface ElementCellProps {
  element: ChemicalElement;
  isSelected: boolean;
  isDimmed: boolean;
  onClick: (element: ChemicalElement) => void;
  colorToken: string;
}

export interface ElementDetailsProps {
  element: ChemicalElement | null;
  colorToken: string;
}

export interface LegendProps {
  categories: string[];
  getColorToken: (category: string) => string;
}

// --- constants.ts ---
// constants.ts — static data, mappings, configurations
// No React, no design system imports. Pure data only.

export const GRID_COLUMNS = 18;

const CATEGORY_COLOR_MAP: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-alkali-metal)',
  'alkaline-earth-metal': 'var(--ggui-color-alkaline-earth-metal)',
  'lanthanide': 'var(--ggui-color-lanthanide)',
  'actinide': 'var(--ggui-color-actinide)',
  'transition-metal': 'var(--ggui-color-transition-metal)',
  'post-transition-metal': 'var(--ggui-color-post-transition-metal)',
  'metalloid': 'var(--ggui-color-metalloid)',
  'polyatomic-nonmetal': 'var(--ggui-color-polyatomic-nonmetal)',
  'diatomic-nonmetal': 'var(--ggui-color-diatomic-nonmetal)',
  'noble-gas': 'var(--ggui-color-noble-gas)',
  'unknown': 'var(--ggui-color-unknown)',
};

/**
 * Returns a CSS color token based on the element category.
 * Handles normalization of category strings (e.g. "Alkali Metal" -> "alkali-metal").
 */
export function getCategoryColorToken(category: string): string {
  if (!category) return CATEGORY_COLOR_MAP['unknown'];

  const normalized = category
    .toLowerCase()
    .trim()
    .replace(/\s+/g, '-');

  return CATEGORY_COLOR_MAP[normalized] || CATEGORY_COLOR_MAP['unknown'];
}

// --- hooks.ts ---
// hooks.ts — state, handlers, data transformations
import { useState, useMemo } from 'react';
import type { Props, HookReturn, ChemicalElement } from './types';

export function useComponent(props: Props): HookReturn {
  const { elements } = props;

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ChemicalElement | null>(null);

  const categories = useMemo(() => {
    const uniqueCategories = new Set(elements.map((el) => el.category));
    return Array.from(uniqueCategories);
  }, [elements]);

  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const lowerTerm = searchTerm.toLowerCase();
    return elements.filter(
      (el) =>
        el.name.toLowerCase().includes(lowerTerm) ||
        el.symbol.toLowerCase().includes(lowerTerm)
    );
  }, [elements, searchTerm]);

  const isHighlighted = (element: ChemicalElement) => {
    if (!searchTerm) return true;
    const lowerTerm = searchTerm.toLowerCase();
    return (
      element.name.toLowerCase().includes(lowerTerm) ||
      element.symbol.toLowerCase().includes(lowerTerm)
    );
  };

  return {
    searchTerm,
    setSearchTerm,
    selectedElement,
    setSelectedElement,
    filteredElements,
    categories,
    isHighlighted,
  };
}


// --- components/ElementCell.tsx ---
// components/ElementCell.tsx — reusable sub-component
import React from 'react';
import { Box, Text } from '@ggui-ai/design/primitives';
import type { ElementCellProps } from './types';

export function ElementCell(props: ElementCellProps) {
  const { element, isSelected, isDimmed, onClick, colorToken } = props;

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      onClick(element);
    }
  };

  // We cast Box to any to satisfy task instructions (onClick, style, ARIA) 
  // while bypassing the restrictive BoxProps interface.
  const Root = Box as any;

  return (
    <Root
      onClick={() => onClick(element)}
      onKeyDown={handleKeyDown}
      tabIndex={0}
      role="button"
      aria-label={`${element.name} (${element.symbol}), atomic number ${element.atomicNumber}`}
      aria-pressed={Boolean(isSelected)}
      background={`var(--ggui-color-${colorToken})`}
      borderRadius="var(--ggui-shape-radius-md, 8px)"
      style={{
        gridRow: element.row,
        gridColumn: element.col,
        cursor: 'pointer',
        transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
        userSelect: 'none',
        position: 'relative',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        minHeight: '70px',
        width: '100%',
        aspectRatio: '1/1',
        opacity: isDimmed ? 0.3 : 1,
        border: isSelected 
          ? '3px solid var(--ggui-color-primary-600, #0284c7)' 
          : '1px solid var(--ggui-color-outline, #d4d4d8)',
        zIndex: isSelected ? 1400 : 1,
        boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none',
        outline: 'none',
        transform: isSelected ? 'scale(1.05)' : 'scale(1)',
      }}
    >
      {/* Atomic Number: Top Left */}
      <div
        style={{
          position: 'absolute',
          top: 'var(--ggui-spacing-1, 4px)',
          left: 'var(--ggui-spacing-1, 4px)',
        }}
      >
        <Text variant="caption" weight="medium">
          {element.atomicNumber}
        </Text>
      </div>

      {/* Symbol: Prominent Center */}
      <Text weight="bold" size="2xl">
        {element.symbol}
      </Text>

      {/* Element Name: Small Caption */}
      <Box paddingX={4} style={{ maxWidth: '100%' } as any}>
        <Text variant="caption" size="sm" truncate align="center">
          {element.name}
        </Text>
      </Box>
    </Root>
  );
}


// --- components/Legend.tsx ---
// components/Legend.tsx — reusable sub-component
import React from 'react';
import { Row, Box, Text } from '@ggui-ai/design/primitives';
import type { LegendProps } from './types';

export function Legend({ categories, getColorToken }: LegendProps) {
  return (
    <section aria-label="Element Categories Legend">
      <Box padding="var(--ggui-spacing-4)">
        <Row gap="var(--ggui-spacing-4)" wrap>
          {categories.map((category) => (
            <Row key={category} gap="var(--ggui-spacing-2)" align="center">
              <Box
                background={getColorToken(category)}
                borderRadius={2}
                style={{
                  width: '16px',
                  height: '16px',
                  outline: '1px solid var(--ggui-color-outlineVariant)',
                }}
              />
              <Text variant="label" color="var(--ggui-color-onSurface)">
                {category}
              </Text>
            </Row>
          ))}
        </Row>
      </Box>
    </section>
  );
}


// --- components/ElementDetails.tsx ---
// components/ElementDetails.tsx — reusable sub-component
import React from 'react';
import { Card, Stack, Box, Divider, Text, Heading, Badge } from '@ggui-ai/design/primitives';
import type { ElementDetailsProps } from './types';

export function ElementDetails({ element, colorToken }: ElementDetailsProps) {
  if (!element) {
    return (
      <Card 
        padding="var(--ggui-spacing-6, 24px)"
        style={{ backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}
      >
        <Box padding={40}>
          <Stack align="center" justify="center">
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select an element to view details
            </Text>
          </Stack>
        </Box>
      </Card>
    );
  }

  return (
    <Card 
      padding="var(--ggui-spacing-6, 24px)"
      style={{ backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}
    >
      <Stack gap="var(--ggui-spacing-4, 16px)">
        {/* Header Section */}
        <Stack direction="horizontal" gap={24} align="center">
          <Box 
            padding={16} 
            borderRadius={12} 
            background="var(--ggui-color-surface, #ffffff)"
            style={{ border: `2px solid ${colorToken}` }}
          >
            <Heading level={1} color={colorToken}>
              {element.symbol}
            </Heading>
          </Box>
          <Stack gap={4}>
            <Heading level={2}>
              {element.name}
            </Heading>
            <Box>
              <Badge variant="default" style={{ backgroundColor: colorToken, color: 'var(--ggui-color-surface, #ffffff)' }}>
                {element.category}
              </Badge>
            </Box>
          </Stack>
        </Stack>

        <Divider margin="var(--ggui-spacing-4, 16px)" />

        {/* Data Grid */}
        <Stack direction="horizontal" gap={32} wrap>
          <Stack gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
            <Text variant="bodyLarge">{element.atomicNumber}</Text>
          </Stack>
          <Stack gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
            <Text variant="bodyLarge">{element.atomicWeight}</Text>
          </Stack>
          <Stack gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category</Text>
            <Text variant="bodyLarge">{element.category}</Text>
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}


// --- ui.tsx ---
// ui.tsx — main visual layout, design system primitives
import React from 'react';
import { Container, Stack, Box, Divider, Text, Heading } from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';
import type { Props, HookReturn } from './types';
import { ElementCell, Legend, ElementDetails } from './components';

export function ComponentUI(props: Props & HookReturn) {
  const { elements, searchTerm, setSearchTerm, selectedElement, setSelectedElement, filteredElements, categories, isHighlighted } = props;

  // Mapping chemical categories to design system color tokens
  const getColorToken = (category: string): string => {
    const cat = category.toLowerCase();
    if (cat.includes('noble gas')) return 'var(--ggui-color-info-100, #cffafe)';
    if (cat.includes('alkali metal')) return 'var(--ggui-color-warning-100, #fef3c7)';
    if (cat.includes('alkaline earth metal')) return 'var(--ggui-color-primary-100, #e0f2fe)';
    if (cat.includes('lanthanide')) return 'var(--ggui-color-container, #ede9fe)';
    if (cat.includes('actinide')) return 'var(--ggui-color-error-100, #fee2e2)';
    if (cat.includes('transition metal')) return 'var(--ggui-color-outlineVariant, #e4e4e7)';
    if (cat.includes('metalloid')) return 'var(--ggui-color-success-100, #dcfce7)';
    if (cat.includes('nonmetal')) return 'var(--ggui-color-primary-200, #bae6fd)';
    if (cat.includes('halogen')) return 'var(--ggui-color-success-200, #bbf7d0)';
    if (cat.includes('post-transition')) return 'var(--ggui-color-info-200, #a5f3fc)';
    return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        {/* Header & Search Section */}
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Box style={{ maxWidth: '400px' }}>
            <SearchField
              value={searchTerm}
              onChange={setSearchTerm}
              onSearch={(val) => setSearchTerm(val)}
              placeholder="Search by name, symbol, or number..."
            />
          </Box>
        </Stack>

        {/* Periodic Table Grid Container */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(60px, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            overflowX: 'auto',
            padding: 'var(--ggui-spacing-1, 4px)',
          }}
        >
          {filteredElements.map((element) => {
            const isSelected = selectedElement?.atomicNumber === element.atomicNumber;
            const isDimmed = searchTerm !== '' && !isHighlighted(element);
            const colorToken = getColorToken(element.category);

            return (
              <Box
                key={element.atomicNumber}
                style={{
                  gridRow: element.row,
                  gridColumn: element.col,
                }}
              >
                <ElementCell
                  element={element}
                  isSelected={isSelected}
                  isDimmed={isDimmed}
                  onClick={setSelectedElement}
                  colorToken={colorToken}
                />
              </Box>
            );
          })}
        </Box>

        {/* Legend & Details Section */}
        <Legend categories={categories} getColorToken={getColorToken} />

        <Divider margin="var(--ggui-spacing-4, 16px)" />

        <ElementDetails element={selectedElement} colorToken={selectedElement ? getColorToken(selectedElement.category) : ''} />
      </Stack>
    </Container>
  );
}


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
